func maxSumSubarray(nums []int, k int) int {
    window := 0
    for i := 0; i < k; i++ {
        window += nums[i]
    }
    best := window
    for i := k; i < len(nums); i++ {
        window += nums[i] - nums[i-k]
        if window > best {
            best = window
        }
    }
    return best
}

func main() {
    fmt.Println(maxSumSubarray([]int{2, 1, 5, 1, 3, 2}, 3))  // 9
}

