func twoSumSorted(nums []int, target int) (int, int) {
    left, right := 0, len(nums)-1
    for left < right {
        s := nums[left] + nums[right]
        if s == target {
            return left, right
        } else if s < target {
            left++
        } else {
            right--
        }
    }
    return -1, -1
}

func main() {
    l, r := twoSumSorted([]int{1, 3, 5, 7, 10}, 8)
    fmt.Println(l, r)  // 0 4
}

