    nums := []int{3, 1, 4, 1, 5}
    prefix := make([]int, len(nums)+1)
    for i := range nums {
        prefix[i+1] = prefix[i] + nums[i]
    }
    // Range sum [1..3] = 1+4+1 = 6
    fmt.Println(prefix[4] - prefix[1])  // 6
}

